const { randomUUID } = require('../../lib/id');

let tasksStore = [];

const createTask = (projectId, title) => {
  const taskId = randomUUID();
  const task = { id: taskId, projectId, title, status: 'todo' };
  tasksStore.push(task);
  return task;
};

const getTasks = (projectId) => {
  return tasksStore.filter(task => task.projectId === projectId);
};

const updateTaskStatus = (projectId, taskId, status) => {
  const task = tasksStore.find(t => t.id === taskId && t.projectId === projectId);
  if (!task) {
    return null;
  }
  task.status = status;
  return task;
};

module.exports = { createTask, getTasks, updateTaskStatus };
